import { Component, OnInit } from '@angular/core';
import { Student, StudentService } from '../../../core/services/student.service';
import { BulletinService, BulletinData } from '../../../core/services/bulletin.service';
import { NotificationService } from '../../../core/services/notification.service';
import { SchoolDataService } from '../../../core/services/school-data.service';

@Component({
  selector: 'app-bulletin',
  templateUrl: './bulletin.component.html',
  styleUrls: ['./bulletin.component.css']
})
export class BulletinComponent implements OnInit {
  students: Student[] = [];
  selectedStudent: Student | null = null;
  bulletinData: BulletinData | null = null;
  selectedTerm = '';
  terms = ['Trimestre 1', 'Trimestre 2', 'Trimestre 3'];
  loading = false;
  allBulletins: BulletinData[] = [];
  showAllBulletins = false;
  currentDate = new Date();

  // Mode de génération
  generationMode: 'individual' | 'class' | 'college' | 'lycee' | 'school' = 'individual';

  // Filtres
  classes: string[] = [];
  selectedClass = '';
  selectedLevel = '';

  constructor(
    private studentService: StudentService,
    private bulletinService: BulletinService,
    private notification: NotificationService,
    private schoolData: SchoolDataService
  ) {
    this.classes = this.schoolData.classes;
  }

  ngOnInit() {
    this.studentService.getAll().subscribe(s => this.students = s);
  }

  loadBulletin() {
    if (!this.selectedStudent) {
      this.notification.warning('Sélectionnez un étudiant');
      return;
    }

    this.loading = true;
    this.bulletinService.getBulletinData(this.selectedStudent.id!, this.selectedTerm).subscribe({
      next: (data) => {
        this.bulletinData = data;
        this.loading = false;
      },
      error: () => {
        this.notification.error('Erreur lors du chargement du bulletin');
        this.loading = false;
      }
    });
  }

  generateBulletins() {
    this.loading = true;
    this.allBulletins = [];
    this.showAllBulletins = true;

    let studentsToProcess: Student[] = [];

    switch (this.generationMode) {
      case 'individual':
        if (!this.selectedStudent) {
          this.notification.warning('Sélectionnez un étudiant');
          this.loading = false;
          return;
        }
        studentsToProcess = [this.selectedStudent];
        break;

      case 'class':
        if (!this.selectedClass) {
          this.notification.warning('Sélectionnez une classe');
          this.loading = false;
          return;
        }
        // Filtrer par classe (à améliorer avec un vrai champ className)
        studentsToProcess = this.students; // Pour l'instant, tous les étudiants
        break;

      case 'college':
        // Filtrer les étudiants du collège
        studentsToProcess = this.students.filter(s => {
          // Logique simplifiée - à améliorer
          return true;
        });
        break;

      case 'lycee':
        // Filtrer les étudiants du lycée
        studentsToProcess = this.students.filter(s => {
          // Logique simplifiée - à améliorer
          return true;
        });
        break;

      case 'school':
        studentsToProcess = this.students;
        break;
    }

    this.notification.info(`Génération de ${studentsToProcess.length} bulletin(s)...`);

    let completed = 0;
    studentsToProcess.forEach(student => {
      this.bulletinService.getBulletinData(student.id!, this.selectedTerm).subscribe({
        next: (data) => {
          this.allBulletins.push(data);
          completed++;
          if (completed === studentsToProcess.length) {
            this.notification.success(`${this.allBulletins.length} bulletin(s) généré(s) avec succès`);
            this.loading = false;
          }
        },
        error: () => {
          completed++;
          if (completed === studentsToProcess.length) {
            this.loading = false;
          }
        }
      });
    });
  }

  printBulletin() {
    window.print();
  }

  downloadBulletin() {
    this.notification.info('Téléchargement du bulletin...');
    setTimeout(() => {
      this.notification.success('Bulletin téléchargé');
    }, 1000);
  }

  downloadAllBulletins() {
    this.notification.info('Téléchargement de tous les bulletins...');
    setTimeout(() => {
      this.notification.success(`${this.allBulletins.length} bulletin(s) téléchargé(s)`);
    }, 2000);
  }

  getGradeLevel(score: number): string {
    if (score >= 16) return 'Excellent';
    if (score >= 14) return 'Bien';
    if (score >= 12) return 'Assez bien';
    if (score >= 10) return 'Passable';
    return 'Insuffisant';
  }

  getGradeClass(score: number): string {
    if (score >= 16) return 'grade-excellent';
    if (score >= 14) return 'grade-bien';
    if (score >= 12) return 'grade-assez-bien';
    if (score >= 10) return 'grade-passable';
    return 'grade-insuffisant';
  }
}
